func solve(s: String) -> String {
    var result = ""
    for char in s {
        if char == "*" {
            if !result.isEmpty {
                result.removeLast()
            }
        } else if char == "#" {
            result = result + result
        } else if char == "%" {
            result = String(result.reversed())
        } else {
            result.append(char)
        }
    }
    return result
}
```

